import React, { useState, useEffect } from 'react';
import SplitText from './components/SplitText/SplitText';
import LogoLoop from './components/LogoLoop/LogoLoop';
import AnimatedList from './components/AnimatedList/AnimatedList';
import qrcode from './images/1778377124951.png';
import './App.css';

function App() {
  const [showIntro, setShowIntro] = useState(true);
  const [showQR, setShowQR] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => {
      setShowIntro(false);
    }, 1800);
    return () => clearTimeout(timer);
  }, []);

  if (showIntro) {
    return (
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        width: '100%',
        height: '100vh',
        background: '#0a0a1a',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        zIndex: 9999
      }}>
        <h1 className="hello-text">Hello 👋</h1>
      </div>
    );
  }

  // 👇 点击列表项的处理函数
  const handleItemSelect = (item, index) => {
    console.log(item, index);
    if (item === '🎨 设计与开发') {   // 👈 点击这个就弹窗
      setShowQR(true);
    }
  };

  const listItems = [
    '🚀 探索创意空间',
    '🎨 设计与开发',
    '💡 灵感与创新',
    '🛠️ 技术栈展示',
    '📱 响应式设计',
    '🔮 动画交互',
    '⚡ 高性能优化',
    '🌐 全栈开发',
    '📦 组件化架构',
  ];

  return (
    <div className="App" style={{ minHeight: '100vh' }}>
      {showQR && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '100%',
          height: '100vh',
          background: 'rgba(0,0,0,0.8)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 9999,
          backdropFilter: 'blur(10px)',
        }} onClick={() => setShowQR(false)}>
          <div style={{
            background: '#1a1a2e',
            padding: '2rem',
            borderRadius: '1rem',
            textAlign: 'center',
          }} onClick={e => e.stopPropagation()}>
            <h3 style={{ color: 'white', marginBottom: '1rem' }}>扫码赞赏 💙</h3>
            <img src={qrcode} alt="收款码" style={{ width: '250px', borderRadius: '0.5rem' }} />
            <p style={{ color: '#999', marginTop: '1rem', fontSize: '0.9rem' }}>点击空白处关闭</p>
          </div>
        </div>
      )}

      <div style={{ position: 'relative', zIndex: 1 }}>
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: '100vh'
        }}>
          <div style={{ animation: 'fadeInWrapper 0.01s 0.3s both' }}>
            <SplitText
              text="欢迎来到创意空间"
              tag="h1"
              delay={80}
              duration={0.8}
              ease="power3.out"
              splitType="chars"
              from={{ opacity: 0, y: 60 }}
              to={{ opacity: 1, y: 0 }}
              textAlign="center"
            />
          </div>
        </div>

        <section style={{
          padding: '4rem 2rem',
          display: 'flex',
          justifyContent: 'center',
        }}>
          <AnimatedList
            items={listItems}
            onItemSelect={handleItemSelect}   // 👈 用这个处理函数
            showGradients={false}
            enableArrowNavigation={true}
            displayScrollbar={true}
          />
        </section>

        <div style={{
          background: 'rgba(255, 255, 255, 0.1)',
          backdropFilter: 'blur(10px)',
          padding: '2rem 0',
          marginTop: '2rem',
          marginBottom: '2rem',
          position: 'relative',
          zIndex: 10
        }}>
          <LogoLoop
            logos={[
              { node: <span style={{color:'white', fontSize:'24px', fontWeight:'bold'}}>React</span> },
              { node: <span style={{color:'white', fontSize:'24px', fontWeight:'bold'}}>Vue</span> },
              { node: <span style={{color:'white', fontSize:'24px', fontWeight:'bold'}}>Next.js</span> },
              { node: <span style={{color:'white', fontSize:'24px', fontWeight:'bold'}}>Node.js</span> },
              { node: <span style={{color:'white', fontSize:'24px', fontWeight:'bold'}}>Python</span> },
              { node: <span style={{color:'white', fontSize:'24px', fontWeight:'bold'}}>Git</span> },
            ]}
            speed={100}
            direction="left"
            logoHeight={30}
            gap={60}
            hoverSpeed={0}
            scaleOnHover
          />
        </div>
      </div>
    </div>
  );
}

export default App;